import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Modifier;

class ConstructorConstructorTest {

  @Test
  void checkInstantiable_withInterface_returnsErrorMessage() {
    Class<?> interfaceClass = Runnable.class; // Runnable is an interface
    String result = ConstructorConstructor.checkInstantiable(interfaceClass);
    assertNotNull(result);
    assertTrue(result.contains("Interfaces can't be instantiated!"));
    assertTrue(result.contains(interfaceClass.getName()));
  }

  @Test
  void checkInstantiable_withAbstractClass_returnsErrorMessage() {
    abstract class AbstractClass {}
    String result = ConstructorConstructor.checkInstantiable(AbstractClass.class);
    assertNotNull(result);
    assertTrue(result.contains("Abstract classes can't be instantiated!"));
    assertTrue(result.contains(AbstractClass.class.getName()));
  }

  @Test
  void checkInstantiable_withConcreteClass_returnsNull() {
    class ConcreteClass {}
    String result = ConstructorConstructor.checkInstantiable(ConcreteClass.class);
    assertNull(result);
  }

  @Test
  void checkInstantiable_withEnum_returnsNull() {
    enum TestEnum {A, B}
    String result = ConstructorConstructor.checkInstantiable(TestEnum.class);
    assertNull(result);
  }

  @Test
  void checkInstantiable_withPrimitive_returnsNull() {
    String result = ConstructorConstructor.checkInstantiable(int.class);
    assertNull(result);
  }
}
